module A();	// spurious_error.mlir:1:1
  B b (	// spurious_error.mlir:3:3
  //.c (<<unsupported zero width constant: hw.constant>>)	// spurious_error.mlir:2:8
  );
endmodule

module B(	// spurious_error.mlir:5:1
  // input /*Zero Width*/ c
   );

endmodule
```

